#!/bin/bash\n\nWEBSITE_PATH=\"$1\"\nSUBDOMAIN=\"$2\"\nDOMAIN=\"sites.friendify.cloud\"\nFULL_DOMAIN=\"${SUBDOMAIN}.${DOMAIN}\"\nTEMP_DIR=\"/tmp/traefik-deploy-${SUBDOMAIN}-$(date +%s)\"\n\nif [[ ! \"$WEBSITE_PATH\" =~ ^/ ]]; then\n    WEBSITE_PATH=\"$(pwd)/${WEBSITE_PATH}\"\nfi\n\necho \"Deploying website from ${WEBSITE_PATH} to ${FULL_DOMAIN}\"\n\nmkdir -p \"$TEMP_DIR\" || { echo \"Failed to create temporary directory\"; exit 1; }\n\n# Create docker-compose.yml\ncat <<EOF > \"$TEMP_DIR/docker-compose.yml\"\nversion: '3.8'\nservices:\n  nginx:\n    image: nginx:alpine\n    container_name: \"${SUBDOMAIN}-web\"\n    labels:\n      - \"traefik.enable=true\"\n      - \"traefik.http.routers.${SUBDOMAIN}-router.rule=Host(\`${FULL_DOMAIN}\`)\"\n      - \"traefik.http.routers.${SUBDOMAIN}-router.entrypoints=websecure\"\n      - \"traefik.http.routers.${SUBDOMAIN}-router.tls=true\"\n      - \"traefik.http.routers.${SUBDOMAIN}-router.tls.certresolver=le\"\n      - \"traefik.http.services.${SUBDOMAIN}-service.loadbalancer.server.port=80\"\n    networks:\n      - web\n\nnetworks:\n  web:\n    external: true\nEOF\n\necho \"Generated docker-compose.yml in $TEMP_DIR:\"\ncat \"$TEMP_DIR/docker-compose.yml\"\n\ndocker network inspect web >/dev/null 2>&1 || docker network create web || { echo \"Failed to ensure 'web' docker network exists\"; exit 1; }\n\npushd \"$TEMP_DIR\" || { echo \"Failed to change directory to $TEMP_DIR\"; exit 1; }\ndocker compose up -d || { echo \"Failed to start docker compose services\"; popd; exit 1; }\npopd\n\nCONTAINER_NAME=\"${SUBDOMAIN}-web\"\n# Give it a moment to start\nsleep 5\necho \"Copying files from ${WEBSITE_PATH} to ${CONTAINER_NAME}:/usr/share/nginx/html\"\ndocker cp \"${WEBSITE_PATH}/.\" \"${CONTAINER_NAME}:/usr/share/nginx/html\" || { echo \"Failed to copy files to container\"; exit 1; }\n\necho \"Website deployed and should be accessible at https://${FULL_DOMAIN}\"\n\n# Record deployment\nDEPLOYMENTS_FILE=\"/data/.openclaw/workspace/publish-website-traefik/deployments.json\"\nDEPLOYMENT_URL=\"https://${FULL_DOMAIN}\"\n\njq --arg subdomain \"$SUBDOMAIN\" \n   --arg temp_dir \"$TEMP_DIR\" \n   --arg container_name \"$CONTAINER_NAME\" \n   --arg url \"$DEPLOYMENT_URL\" \n   '. + {($subdomain): {\"temp_dir\": \"$temp_dir\", \"container_name\": \"$container_name\", \"url\": \"$url\"}}' \n   \"$DEPLOYMENTS_FILE\" > \"${DEPLOYMENTS_FILE}.tmp\" && mv \"${DEPLOYMENTS_FILE}.tmp\" \"$DEPLOYMENTS_FILE\"\n\necho \"Deployment recorded in ${DEPLOYMENTS_FILE}\"\necho \"Cleanup: To remove this deployment, use the delete_site.sh script: ./scripts/delete_site.sh ${SUBDOMAIN}\"\n